  1	import * as React from 'react';
  2	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  3	import { useGetClusterDetails } from '@odf/core/redux/utils';
  4	import { ObjectStorageEfficiencyQueries } from '@odf/ocs/queries';
  5	import { EfficiencyItemBody } from '@odf/shared/dashboards/storage-efficiency/storage-efficiency-card-item';
  6	import { DataUnavailableError } from '@odf/shared/generic';
  7	import {
  8	  useCustomPrometheusPoll,
  9	  usePrometheusBasePath,
 10	} from '@odf/shared/hooks/custom-prometheus-poll';
 11	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 12	import { humanizeBinaryBytes, humanizePercentage } from '@odf/shared/utils';
 13	import { getGaugeValue } from '@odf/shared/utils';
 14	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
 15	
 16	const ObjectStorageEfficiencyItemBody: React.FC = () => {
 17	  const { t } = useCustomTranslation();
 18	
 19	  const [compressionQueryResult, compressionQueryResultError] =
 20	    useCustomPrometheusPoll({
 21	      query: ObjectStorageEfficiencyQueries.COMPRESSION_RATIO,
 22	      endpoint: 'api/v1/query' as any,
 23	      basePath: usePrometheusBasePath(),
 24	    });
 25	  const [savingsQueryResult, savingsQueryResultError] = useCustomPrometheusPoll(
 26	    {
 27	      query: ObjectStorageEfficiencyQueries.SAVINGS_QUERY,
 28	      endpoint: 'api/v1/query' as any,
 29	      basePath: usePrometheusBasePath(),
 30	    }
 31	  );
 32	  const [logicalSavingsQueryResult, logicalSavingsQueryResultError] =
 33	    useCustomPrometheusPoll({
 34	      query: ObjectStorageEfficiencyQueries.LOGICAL_SAVINGS_QUERY,
 35	      endpoint: 'api/v1/query' as any,
 36	      basePath: usePrometheusBasePath(),
 37	    });
 38	
 39	  const compressionRatio = getGaugeValue(compressionQueryResult);
 40	  const savings = getGaugeValue(savingsQueryResult);
 41	  const logicalSize = getGaugeValue(logicalSavingsQueryResult);
 42	
 43	  const compressionStats = () => {
 44	    const capacityRatio = Number(compressionRatio);
 45	    return t('{{capacityRatio, number}}:1', {
 46	      capacityRatio: Math.round(capacityRatio),
 47	    });
 48	  };
 49	
 50	  const savingStats = () => {
 51	    const savedBytes = humanizeBinaryBytes(Number(savings)).string;
 52	    const savingsPercentage = `${savedBytes} (${
 53	      humanizePercentage((100 * Number(savings)) / Number(logicalSize)).string
 54	    })`;
 55	    return savingsPercentage;
 56	  };
 57	
 58	  const compressionRatioProps = {
 59	    stats: Number(compressionRatio),
 60	    isLoading: !compressionQueryResult && !compressionQueryResultError,
 61	    error:
 62	      !!compressionQueryResultError ||
 63	      !compressionRatio ||
 64	      Number(compressionRatio) === 1,
 65	    title: t('Compression ratio'),
 66	    infoText: t(
 67	      'Data Foundation can be configured to use compression. The efficiency rate reflects the actual compression ratio when using such a configuration.'
 68	    ),
 69	    getStats: compressionStats,
 70	  };
 71	
 72	  const savingsProps = {
 73	    stats: Number(savings),
 74	    isLoading:
 75	      !savingsQueryResult &&
 76	      !logicalSavingsQueryResult &&
 77	      !savingsQueryResultError,
 78	    error:
 79	      !!savingsQueryResultError ||
 80	      !!logicalSavingsQueryResultError ||
 81	      !savings ||
 82	      !logicalSize,
 83	    title: t('Savings'),
 84	    infoText: t(
 85	      'Savings shows the uncompressed and non-deduped data that would have been stored without those techniques.'
 86	    ),
 87	    getStats: savingStats,
 88	  };
 89	
 90	  return (
 91	    <>
 92	      <EfficiencyItemBody {...compressionRatioProps} />
 93	      <EfficiencyItemBody {...savingsProps} />
 94	    </>
 95	  );
 96	};
 97	
 98	const StorageEfficiencyCard: React.FC<{}> = () => {
 99	  const { t } = useCustomTranslation();
100	
101	  const { clusterNamespace: clusterNs } = useGetClusterDetails();
102	  const { systemFlags } = useODFSystemFlagsSelector();
103	  const hasMCG = systemFlags[clusterNs]?.isNoobaaAvailable;
104	
105	  return (
106	    <Card>
107	      <CardHeader>
108	        <CardTitle>{t('Storage efficiency')}</CardTitle>
109	      </CardHeader>
110	      <CardBody>
111	        {hasMCG ? (
112	          <ObjectStorageEfficiencyItemBody />
113	        ) : (
114	          <DataUnavailableError />
115	        )}
116	      </CardBody>
117	    </Card>
118	  );
119	};
120	
121	export default StorageEfficiencyCard;

